import pandas as pd
from geopy.geocoders import Nominatim
from geopy.exc import GeocoderTimedOut

def validate_coordinates(address, latitude, longitude):
    geolocator = Nominatim(user_agent="geoapiExercises")

    try:
        location = geolocator.geocode(address)
        if not location:
            return False

        # Check if the provided latitude and longitude match the geocoded location
        return (location.latitude == latitude) and (location.longitude == longitude)
    except GeocoderTimedOut:
        return False

def solve(csv_file):
    df = pd.read_csv(csv_file)
    results = []

    for index, row in df.iterrows():
        address = row['address']
        latitude = row['latitude']
        longitude = row['longitude']

        is_valid = validate_coordinates(address, latitude, longitude)
        results.append({
            'address': address,
            'latitude': latitude,
            'longitude': longitude,
            'is_valid': is_valid
        })

    return results
